<script setup>
import {onMounted,reactive,ref} from 'vue';import {getMembers} from '../api/memberApi';import {createRepair,deleteRepair,getRepairs,updateRepair} from '../api/repairApi'
const repairs=ref([]),members=ref([]),loading=ref(false),saving=ref(false),errorMessage=ref(''),editingId=ref(null);const filters=reactive({keyword:'',status:''})
const blank=()=>({memberId:'',deviceBrand:'',deviceModel:'',imei:'',problemDescription:'',repairStatus:'RECEIVED',estimatedCost:null,finalCost:null,receivedDate:'',expectedCompletionDate:'',completedDate:'',technicianName:'',repairNotes:''});const form=reactive(blank());const labels={RECEIVED:'已收件',INSPECTING:'檢測中',WAITING_PARTS:'等待零件',REPAIRING:'維修中',COMPLETED:'已完成',RETURNED:'已交還',CANCELLED:'已取消'};const money=v=>v==null?'-':new Intl.NumberFormat('zh-TW',{style:'currency',currency:'TWD'}).format(v);const date=v=>v||'-';const message=e=>e?.response?.data?.message||e?.message||'操作失敗，請稍後再試'
async function load(){loading.value=true;errorMessage.value='';try{repairs.value=await getRepairs(Object.fromEntries(Object.entries(filters).filter(([,v])=>v)))}catch(e){errorMessage.value=message(e)}finally{loading.value=false}}
function edit(r){editingId.value=r.id;Object.assign(form,{memberId:r.memberId,deviceBrand:r.deviceBrand,deviceModel:r.deviceModel,imei:r.imei||'',problemDescription:r.problemDescription,repairStatus:r.repairStatus,estimatedCost:r.estimatedCost,finalCost:r.finalCost,receivedDate:r.receivedDate||'',expectedCompletionDate:r.expectedCompletionDate||'',completedDate:r.completedDate||'',technicianName:r.technicianName||'',repairNotes:r.repairNotes||''});scrollTo({top:0,behavior:'smooth'})}function reset(){editingId.value=null;Object.assign(form,blank())}const nullableNumber=v=>v===''||v==null?null:Number(v);const nullable=v=>v||null
async function submit(){saving.value=true;errorMessage.value='';try{const data={...form,memberId:Number(form.memberId),estimatedCost:nullableNumber(form.estimatedCost),finalCost:nullableNumber(form.finalCost),receivedDate:nullable(form.receivedDate),expectedCompletionDate:nullable(form.expectedCompletionDate),completedDate:nullable(form.completedDate)};editingId.value?await updateRepair(editingId.value,data):await createRepair(data);reset();await load()}catch(e){errorMessage.value=message(e)}finally{saving.value=false}}
async function remove(r){if(!confirm(`確定刪除維修單 #${r.id}？`))return;try{await deleteRepair(r.id);await load()}catch(e){errorMessage.value=message(e)}}function clear(){Object.assign(filters,{keyword:'',status:''});load()}onMounted(async()=>{try{members.value=await getMembers();await load()}catch(e){errorMessage.value=message(e)}})
</script>
<template><section class="management-page"><div class="page-heading"><div><h2>維修管理</h2><p>管理手機送修資料、費用與維修進度。</p></div><button class="secondary" :disabled="loading" @click="load">{{loading?'載入中...':'重新整理'}}</button></div><p v-if="errorMessage" class="alert error">{{errorMessage}}</p>
<form class="card" @submit.prevent="submit"><h3>{{editingId?`編輯維修單 #${editingId}`:'新增維修單'}}</h3><div class="form-grid"><label>會員 *<select v-model="form.memberId" required><option value="" disabled>請選擇</option><option v-for="m in members" :key="m.id" :value="m.id">{{m.id}}－{{m.account}}－{{m.name}}</option></select></label><label>品牌 *<input v-model.trim="form.deviceBrand" required></label><label>型號 *<input v-model.trim="form.deviceModel" required></label><label>IMEI<input v-model.trim="form.imei"></label><label>狀態<select v-model="form.repairStatus"><option v-for="(label,key) in labels" :key="key" :value="key">{{label}}</option></select></label><label>技師<input v-model.trim="form.technicianName"></label><label>預估費用<input v-model.number="form.estimatedCost" type="number" min="0" step="0.01"></label><label>最終費用<input v-model.number="form.finalCost" type="number" min="0" step="0.01"></label><label>收件日期<input v-model="form.receivedDate" type="date"></label><label>預計完成日期<input v-model="form.expectedCompletionDate" type="date"></label><label>完成日期<input v-model="form.completedDate" type="date"></label><label class="full-width">問題描述 *<textarea v-model.trim="form.problemDescription" required rows="3"></textarea></label><label class="full-width">維修備註<textarea v-model.trim="form.repairNotes" rows="3"></textarea></label></div><div class="form-actions"><button class="primary" :disabled="saving">{{saving?'處理中...':editingId?'儲存修改':'新增維修單'}}</button><button v-if="editingId" type="button" class="secondary" @click="reset">取消編輯</button></div></form>
<form class="card search-bar" @submit.prevent="load"><label>關鍵字<input v-model.trim="filters.keyword" placeholder="會員、品牌或型號"></label><label>狀態<select v-model="filters.status"><option value="">全部</option><option v-for="(label,key) in labels" :key="key" :value="key">{{label}}</option></select></label><button class="primary">搜尋</button><button type="button" class="secondary" @click="clear">清除</button></form>
<div class="card"><h3>維修單列表</h3><p v-if="loading">載入中...</p><p v-else-if="!repairs.length">目前沒有維修單。</p><div v-else class="table-scroll"><table><thead><tr><th>ID</th><th>會員</th><th>品牌</th><th>型號</th><th>問題描述</th><th>狀態</th><th>預估費用</th><th>最終費用</th><th>收件日期</th><th>預計完成</th><th>技師</th><th>操作</th></tr></thead><tbody><tr v-for="r in repairs" :key="r.id"><td>{{r.id}}</td><td>{{r.memberName}}</td><td>{{r.deviceBrand}}</td><td>{{r.deviceModel}}</td><td class="wrap-cell">{{r.problemDescription}}</td><td><span class="badge">{{labels[r.repairStatus]||r.repairStatus}}</span></td><td>{{money(r.estimatedCost)}}</td><td>{{money(r.finalCost)}}</td><td>{{date(r.receivedDate)}}</td><td>{{date(r.expectedCompletionDate)}}</td><td>{{r.technicianName||'-'}}</td><td class="row-actions"><button class="secondary small" @click="edit(r)">編輯</button><button class="danger small" @click="remove(r)">刪除</button></td></tr></tbody></table></div></div></section></template>
